var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"아빠, 저거 봐! 코끼리다, 코끼리!","JPN":"パパ、あれ見て！　ゾウさんだよ、ゾウさん！","ENG":"Daddy, look! It’s an elephant!","TWN":"爸爸，你看！是大象欸！"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"으음, 그렇구나. 우리에 갇혀 있는 코끼리구나.","JPN":"うーん、そうだね。檻に閉じ込められてるゾウさんだね。","ENG":"Right, right. It’s an elephant in a cage.","TWN":"嗯～是欸，是被人類關起來的大象。"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"먹고 자고 편하게 쉬고 평화로워 보이지만, 결국 저 친구도 울타리에 갇힌 채 벗어나지 못하는 거겠지.","JPN":"食べて寝て休んで平和そうに見えるけど、結局あの子も檻に閉じ込められたまま出られないんだ。","ENG":"Eating, sleeping, and resting, it looks so peaceful. But that friend eventually won’t be able to escape its cage.","TWN":"你看牠有得吃有得睡，一副很安逸的樣子，其實是被關在柵欄裡逃不出去。"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"동물원에서 태어난 저 코끼리는 사바나 초원의 자유를 알고 있을까?","JPN":"動物園で生まれたあのゾウは、サバナ草原での自由を知ってるのかな？","ENG":"Elephants born in the zoo will never know the freedom of Savannah.","TWN":"在動物園裡出生的大象，會知道草原的自由嗎？"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"모르겠지. 분명 모를 거야.","JPN":"知らないだろうな。きっと知らない。","ENG":"They’ll never know. Never.","TWN":"當然不知道囉，怎麼可能知道呢。"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"서커스 직원 아저씨, 저희 아빠가 이상해요.","JPN":"サーカスのおじさん、パパがおかしいよ。","ENG":"Mr. Circus clown, Daddy’s acting weird.","TWN":"馬戲團叔叔，我爸爸好奇怪。"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"흔한 증상이니 괜찮습니다. 사회인들의 비애라는 거죠.","JPN":"よくある症状ですので、大丈夫ですよ。社会人のもの悲しさというものです。","ENG":"It’s a common symptom. It’s called grief of members of society.","TWN":"沒事的，這是正常的反應，可以說是職場人士的悲哀。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"흠… 저도 어른이 되면 아빠처럼 되는 건가요?","JPN":"ふーん……ボクも大人になったらパパみたいになるの？","ENG":"Hmm... Will I be like Daddy if I grow up?","TWN":"嗚…等我長大後也會跟爸爸一樣嗎？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 글쎄요.","JPN":"フフ、どうでしょう。","ENG":"Ha ha, we’ll have to see about that.","TWN":"呵呵，那我就不知道囉～"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"분명한 건 지금은 그런 걱정이 필요 없다는 거죠.","JPN":"確かなのは、今はそんなことを心配する必要がないということです。","ENG":"One thing for sure is that you don’t have to worry about stuff like that now.","TWN":"我只知道，現在的你還不需要擔心這種事。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"먼 미래를 걱정하는 건, 그날의 당신이 가질 몫이니까요.","JPN":"遠い未来を心配するのは、未来のあなたの務めですから。","ENG":"It’s up to the future you to worry about the distant future.","TWN":"未來的事，就交給未來的你去擔心吧。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘은 그저 코끼리와 악어를 구경하면서 즐겁게 시간을 보내는 겁니다.","JPN":"今日はただ、ゾウさんとワニさんを見ながら楽しく過ごすのです。","ENG":"You shall just enjoy today, looking at the crocodiles and elephants.","TWN":"今天的你，只需要好好欣賞大象和鱷魚，度過開心的一天。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"…그렇구나.","JPN":"……そっか。","ENG":"...Okay.","TWN":"…是喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"그치만 저 코끼리 귀만 펄럭거리고 안 움직이는 걸. 시시해.","JPN":"でもあのゾウさん、耳をパタパタしてるだけで動かないよ。つまんない。","ENG":"But that elephant isn’t moving. It’s only flapping its ears. Boring.","TWN":"可是那個大象只有耳朵在動，好無聊喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 아무래도 예정에 없던 퍼레이드가 시작될 모양이군요.","JPN":"フフ、どうやら予定にはなかったパレードが始まりそうですね。","ENG":"Ha ha, it looks like an unexpected parade is about to begin.","TWN":"呵呵，行程之外的遊行好像要開始囉。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"퍼레이드?","JPN":"パレード？","ENG":"A parade?","TWN":"遊行？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです。","ENG":"That's correct.","TWN":"對喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니 당신들은 저기에 있는 전망대로 올라가세요.","JPN":"ですから、あなたたちはあそこにある展望台に上がってください。","ENG":"You two go up to the observatory over there.","TWN":"你們快上去那個瞭望台，"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"퍼레이드를 감상하기엔 안성맞춤인 곳이니까요.","JPN":"パレードを観賞するにはうってつけの場所ですから。","ENG":"It will be the perfect place to watch the parade.","TWN":"那邊的視野看遊行得最清楚。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"응, 알겠어!","JPN":"うん、わかった！","ENG":"Okay!","TWN":"嗯，好！"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};